import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);

  const handleLogout = async () => {
    await logout();
    navigate("/");
  };

  const navLink = "text-sm font-medium text-gray-300 hover:text-[#ff00e0] transition-colors duration-200";

  return (
    <nav style={{ background: "#0a0a0a", borderBottom: "1px solid #2a2a2a" }} className="sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">

          {/* Logo */}
          <Link to="/" className="flex items-center gap-2 shrink-0">
            <span className="text-white font-bold text-lg tracking-wide">
              Hometown<span style={{ color: "#ff00e0" }}>Post</span>
            </span>
          </Link>

          {/* Desktop Nav + Auth */}
          <div className="hidden md:flex items-center gap-5">
            <Link to="/" className={navLink}>Event Listings</Link>
            <Link to="/events/new" className={navLink}>Promote your Event</Link>
            {user && <Link to="/dashboard" className={navLink}>My Events</Link>}

            <div className="w-px h-5 bg-gray-700 mx-1" />

            {user ? (
              <>
                <span className="text-sm text-gray-400 font-medium">{user.username}</span>
                <button onClick={handleLogout} className="btn-secondary text-sm px-4 py-2">Sign Out</button>
                <Link to="/events/new" className="btn-primary text-sm px-4 py-2">+ Post Event</Link>
              </>
            ) : (
              <>
                <Link to="/login" className="btn-secondary text-sm px-4 py-2">Sign In</Link>
                <Link to="/register" className="btn-primary text-sm px-4 py-2">Sign Up</Link>
              </>
            )}
          </div>

          {/* Mobile toggle */}
          <button
            onClick={() => setMenuOpen(!menuOpen)}
            className="md:hidden p-2 text-gray-400 hover:text-white transition-colors"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              {menuOpen
                ? <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                : <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />}
            </svg>
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      {menuOpen && (
        <div style={{ background: "#111", borderTop: "1px solid #2a2a2a" }} className="md:hidden px-4 py-4 space-y-3">
          <Link to="/" className="block text-sm text-gray-300 hover:text-[#ff00e0] py-1" onClick={() => setMenuOpen(false)}>Event Listings</Link>
          {user && <Link to="/dashboard" className="block text-sm text-gray-300 hover:text-[#ff00e0] py-1" onClick={() => setMenuOpen(false)}>My Events</Link>}
          <Link to="/events/new" className="block text-sm text-gray-300 hover:text-[#ff00e0] py-1" onClick={() => setMenuOpen(false)}>Promote your Event</Link>
          <div className="flex gap-3 pt-2">
            {user ? (
              <button onClick={() => { handleLogout(); setMenuOpen(false); }} className="btn-secondary text-sm flex-1">Sign Out</button>
            ) : (
              <>
                <Link to="/login" className="btn-secondary text-sm flex-1 text-center" onClick={() => setMenuOpen(false)}>Sign In</Link>
                <Link to="/register" className="btn-primary text-sm flex-1 text-center" onClick={() => setMenuOpen(false)}>Sign Up</Link>
              </>
            )}
          </div>
        </div>
      )}
    </nav>
  );
}
